import { ProTable } from '@ant-design/pro-components';
import { Button, Popconfirm, Tag, message, Modal, Image, Space } from 'antd';
import { CheckOutlined, CloseOutlined, EyeOutlined } from '@ant-design/icons';
import { useRef, useState } from 'react';
import { getUGCList, approveUGC, rejectUGC } from '@/services/api';

interface UGCItem {
  id: string;
  content: string;
  images: string[];
  author: string;
  authorAvatar: string;
  museum: string;
  status: number;
  createTime: string;
}

const UGCList = () => {
  const actionRef = useRef<any>();
  const [detailVisible, setDetailVisible] = useState(false);
  const [currentRecord, setCurrentRecord] = useState<UGCItem | null>(null);

  const handleApprove = async (id: string) => {
    try {
      const result = await approveUGC(id);
      if (result.success) {
        message.success('审核通过');
        actionRef.current?.reload();
      } else {
        message.error(result.message || '操作失败');
      }
    } catch (error) {
      message.error('操作失败');
    }
  };

  const handleReject = async (id: string) => {
    try {
      const result = await rejectUGC(id);
      if (result.success) {
        message.success('已拒绝');
        actionRef.current?.reload();
      } else {
        message.error(result.message || '操作失败');
      }
    } catch (error) {
      message.error('操作失败');
    }
  };

  const handleViewDetail = (record: UGCItem) => {
    setCurrentRecord(record);
    setDetailVisible(true);
  };

  const columns = [
    {
      title: 'ID',
      dataIndex: 'id',
      width: 80,
      search: false,
    },
    {
      title: '内容',
      dataIndex: 'content',
      ellipsis: true,
      width: 300,
    },
    {
      title: '图片',
      dataIndex: 'images',
      width: 100,
      search: false,
      render: (images: string[]) => (
        images && images.length > 0 ? (
          <Image.PreviewGroup>
            <Image
              src={images[0]}
              width={60}
              height={60}
              style={{ objectFit: 'cover', borderRadius: 4 }}
            />
          </Image.PreviewGroup>
        ) : (
          <span style={{ color: '#999' }}>无图片</span>
        )
      ),
    },
    {
      title: '作者',
      dataIndex: 'author',
      width: 120,
    },
    {
      title: '关联博物馆',
      dataIndex: 'museum',
      width: 150,
    },
    {
